import React from 'react';
import StripeCheckout from 'react-stripe-checkout';
import axios from 'axios';

const StripeCheckoutButton = ({ price }) => {
    const stripePrice = price * 100;
    const publishableKey = 'pk_test_51LJLxKHat1IclGpV702ENq1hq2LX4RyEUKN1PWgJgSlpuSKqsYDxZmxtOAChssdKaiKcm2axN3ewPhSaTe3mRstf00pZEJW2BT';

    const onToken = token => {
        axios.post('/payment', {
            data: {
                amount: stripePrice,
                token
            }
        })
        .then( response => {
            alert('Payment Successful!')
        })
        .catch( error => {
            console.log('Payment error: ', error);
            alert(
                "There was an issue with your payment. Please check that you are using the provided credit card."
            )
        })
    };
    
    return(
    <StripeCheckout
        label='Pay Now'
        name='CRWN Clothing Ltd.'
        billingAddress
        shippingAddress
        image='https://sendeyo.com/up/d/f3eb2117da'
        description={`Your total is $${price}`}
        amount={stripePrice}
        panelLabel='Pay Now'
        token={onToken}
        stripeKey={publishableKey}
    />
    );
};

export default StripeCheckoutButton;
